INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic) VALUES
('95377d2f-ab0b-5fda-b35a-3d163b18183d', 'c0215e23-91f1-4ae9-b39b-b68eff80cb98', 'The science teacher''s lecture was so ___ that we all wanted to learn more about the topic.', '科學老師的講座非常有趣，以至於我們都想了解更多關於這個主題的知識。', 'interesting', 'boring', 'difficult', 'noisy', '字首 inter- (在...之間), 字根 est (存在), 字尾 -ing (令人...的)', 'interest (興趣) + ing (令人...的) → interesting (有趣的)'),
('59b71194-38ae-5b1c-8c6e-e56f37ae17c1', '87f4c3a6-4121-46f4-b4f6-c98aecea1972', 'It is important to stay calm ___ the emergency.', '在緊急情況期間，保持冷靜是很重要的。', 'during', 'despite', 'towards', 'beyond', 'dur- 表示持續或耐久', 'dur 聯想 duration (期間) → during (在...期間)'),
('67804227-6b00-57e4-8be0-c9fea013454d', '5d20b73d-7d29-498d-92b3-52636f5571d1', 'I''d like a ___ of soda, please.', '我想要一罐汽水，謝謝。', 'can', 'cup', 'bag', 'box', '指『罐頭』這個容器。', 'Can 就是罐頭的意思。');
